from . import views

app_name = 'members'

urlpatterns = [
    path('profile/', views.profile_view, name='profile'),
]

# events/urls.py
from django.urls import path
from . import views

app_name = 'events'

urlpatterns = [
    path('', views.event_list, name='event_list'),
